<script setup lang="ts">
// AddMenuSheet — production wiring of the iPhone global AddMenu
// (Components/Navigation/AddMenu.swift), presented from the Home header "+".
//
// Two panes matching iOS exactly: the main menu (Send message / Invite member ▸ /
// Create meeting / Create group / Create study program + the red Record video
// card) and the "Invite member" submenu (Send message / Copy link / QR Code /
// Invite members / Invite contacts). "Invite member" slides to the submenu;
// "QR Code" emits `qr` (the parent runs the invite + ShareInviteSheet flow).
// Every other item dismisses — same as the iPhone, where those rows are print
// stubs or flows that aren't part of this build yet.
//
// Icon SVGs are the asset-catalog vectors already mapped for the /compare
// AddMenu adapter (capture/runners/compare/adapters/AddMenu.mjs).
import { ref, watch } from 'vue'
import AddMenu from '../../../components/card/add-menu/add-menu.vue'
import LeaderMenuOverlay from './leader-menu-overlay.vue'

const props = defineProps<{ open: boolean }>()
const emit = defineEmits<{ close: []; qr: [] }>()

const showSubmenu = ref(false)
watch(
  () => props.open,
  (open) => {
    if (open) showSubmenu.value = false
  },
)

