// Main menu (iOS AddMenu order). "Invite member" opens the submenu; the rest
// dismiss (Send message / Create meeting are print stubs on iOS too; the
// create-group / create-program / record flows aren't part of this build).
const MAIN_ITEMS = [
  { icon: ICON_CHAT, title: 'Send message' },
  { icon: ICON_LINK, title: 'Invite member', showSubmenu: true },
  { icon: ICON_MEETING, title: 'Create meeting' },
  { icon: ICON_GROUP, title: 'Create group' },
  { icon: ICON_STUDY, title: 'Create study program' },
]
const RECORD_ITEM = { icon: ICON_RECORD_VIDEO, title: 'Record video' }

// Invite submenu (iOS InviteMemberSubmenu order). "QR Code" emits `qr`.
const SUBMENU_ITEMS = [
  { icon: ICON_CHAT, title: 'Send message' },
  { icon: ICON_LINK, title: 'Copy link' },
  { icon: ICON_QR, title: 'QR Code' },
  { icon: ICON_INVITE, title: 'Invite members' },
  { icon: ICON_USER, title: 'Invite contacts' },
]

function onSelectMain(index: number): void {
  if (MAIN_ITEMS[index]?.showSubmenu) showSubmenu.value = true
  else emit('close')
}

function onSelectSubmenu(index: number): void {
  if (SUBMENU_ITEMS[index]?.title === 'QR Code') emit('qr')
  else emit('close')
}
</script>

<template>
  <LeaderMenuOverlay :open="open" @close="emit('close')">
    <div class="AddMenuSheet" :class="{ 'AddMenuSheet--submenu': showSubmenu }">
      <div class="AddMenuSheet__track">
        <div class="AddMenuSheet__pane">
          <AddMenu
            :items="MAIN_ITEMS"
            :record-item="RECORD_ITEM"
            @select="onSelectMain"
            @record="emit('close')"
            @close="emit('close')"
          />
        </div>
        <div class="AddMenuSheet__pane">
          <AddMenu
            submenu-title="Invite member"
            :submenu-items="SUBMENU_ITEMS"
            @select-submenu="onSelectSubmenu"
            @back="showSubmenu = false"
            @close="emit('close')"
          />
        </div>
      </div>
    </div>
  </LeaderMenuOverlay>
</template>

<style scoped>
/* Two full-width panes sliding horizontally (iOS main ↔ submenu spring). */
.AddMenuSheet {
  overflow: hidden;
  padding-top: 8px;
}

.AddMenuSheet__track {
  display: flex;
  width: 200%;
  transition: transform 0.3s ease;
}

.AddMenuSheet--submenu .AddMenuSheet__track {
  transform: translateX(-50%);
}

.AddMenuSheet__pane {
  width: 50%;
  flex: 0 0 50%;
}
</style>
